import { describe, it, expect } from "vitest";
import { processScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  describe("Quoting a premium", () => {
    it.todo("should quote a single sword for a new customer's first policy");
    it.todo("should quote a single amulet for a new customer's first policy");
    it.todo("should quote multiple items for a new customer's first policy");
    it.todo("should add a 50% surcharge for a cursed item");
    it.todo("should add a 30% surcharge for a highly enchanted item (enchantment >= 5)");
    it.todo("should apply a 20% loyalty discount for long-standing customers (>= 2 years)");
    it.todo("should apply a 15% discount on contracts after the first");
    it.todo("should quote component items at 25G base premium each");
    it.todo("should apply special 60G base premium for a group of 3 alike components");
  });

  describe("Processing a claim", () => {
    it.todo("should process a basic claim applying the 100G deductible");
    it.todo("should cap claim payout at twice the policy insurance sum");
    it.todo("should reimburse at 50% for items with enchantment >= 8");
    it.todo("should fully reimburse damage to dragon material items");
  });
});

