  customer: { yearsWithMHPCO: number };
  steps: unknown[];
}

const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
};

const INITIAL_ASSESSMENT_SURCHARGE_NUMERATOR = 110;
const PROCESSING_FEE = 5;

export const processScenario = (scenario: Scenario): { results: unknown[] } => {
  const step = scenario.steps[0] as { op: string; items: Array<{ type: string }> };
  const totalBase = step.items.reduce((sum, item) => sum + BASE_PREMIUMS[item.type], 0);
  const premium = Math.ceil(totalBase * INITIAL_ASSESSMENT_SURCHARGE_NUMERATOR / 100) + PROCESSING_FEE;
  return { results: [{ premium }] };
};

