    return sum + afterEnchanted;
  }, 0);
  const premium = Math.ceil(totalBase * INITIAL_ASSESSMENT_SURCHARGE_NUMERATOR / PERCENTAGE_BASE) + PROCESSING_FEE;
  return { results: [{ premium }] };
